// Security: Validate file attachments and sanitize form input
var ALLOWED_TYPES = [
  'application/pdf',
  'image/jpeg',
  'image/png',
  'image/gif',
  'image/webp',
  'application/msword',
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  'application/vnd.ms-excel',
  'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
  'text/plain'
];
var MAX_SIZE = 10 * 1024 * 1024; // 10MB
var BLOCKED_EXT = ['exe','bat','cmd','sh','ps1','vbs','js','msi','dll','scr','com','php','py','rb','pl','jar','wsf','hta','cpl','inf','reg'];

function esc(s) {
  if (!s) return '';
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

var item = $input.first();
var body = item.json.body || item.json;
var isValid = true;
var errorMessage = '';
var hasAttachment = false;
var fileName = '';

var bd = item.binary || {};
var keys = Object.keys(bd);

if (keys.length > 0) {
  hasAttachment = true;
  var file = bd[keys[0]];
  fileName = file.fileName || 'unknown';

  // Validate MIME type
  if (!ALLOWED_TYPES.includes(file.mimeType)) {
    isValid = false;
    errorMessage = 'File type not allowed. Accepted: PDF, JPG, PNG, GIF, DOC, DOCX, XLS, XLSX, TXT.';
  }

  // Validate file size
  if (file.fileSize && file.fileSize > MAX_SIZE) {
    isValid = false;
    errorMessage = 'File exceeds the 10MB size limit.';
  }

  // Block dangerous extensions regardless of MIME type
  var ext = fileName.split('.').pop().toLowerCase();
  if (BLOCKED_EXT.includes(ext)) {
    isValid = false;
    errorMessage = 'File extension ".' + ext + '" is blocked for security reasons.';
  }
}

var fn = esc(body.fullName || '');
var em = esc(body.email || '');
var ph = esc(body.phone || '');
var addr = esc(body.address || '');
var msg = esc(body.message || 'N/A');

var emailHtml = '<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto">'
  + '<div style="background:#1e3a5f;color:#fff;padding:20px;text-align:center">'
  + '<h2 style="margin:0">New Quote Request</h2>'
  + '<p style="margin:5px 0 0;opacity:0.9">Fire Alarm Testing Pro</p></div>'
  + '<div style="padding:20px;background:#f9fafb">'
  + '<table style="width:100%;border-collapse:collapse">'
  + '<tr><td style="padding:10px;border-bottom:1px solid #e5e7eb;font-weight:bold;width:140px">Name</td>'
  + '<td style="padding:10px;border-bottom:1px solid #e5e7eb">' + fn + '</td></tr>'
  + '<tr><td style="padding:10px;border-bottom:1px solid #e5e7eb;font-weight:bold">Email</td>'
  + '<td style="padding:10px;border-bottom:1px solid #e5e7eb"><a href="mailto:' + em + '">' + em + '</a></td></tr>'
  + '<tr><td style="padding:10px;border-bottom:1px solid #e5e7eb;font-weight:bold">Phone</td>'
  + '<td style="padding:10px;border-bottom:1px solid #e5e7eb"><a href="tel:' + ph + '">' + ph + '</a></td></tr>'
  + '<tr><td style="padding:10px;border-bottom:1px solid #e5e7eb;font-weight:bold">Address</td>'
  + '<td style="padding:10px;border-bottom:1px solid #e5e7eb">' + addr + '</td></tr>'
  + '<tr><td style="padding:10px;border-bottom:1px solid #e5e7eb;font-weight:bold">Message</td>'
  + '<td style="padding:10px;border-bottom:1px solid #e5e7eb">' + msg + '</td></tr>'
  + '<tr><td style="padding:10px;font-weight:bold">Attachment</td>'
  + '<td style="padding:10px">' + (hasAttachment ? fileName : 'None') + '</td></tr>'
  + '</table></div>'
  + '<div style="padding:15px;background:#e5e7eb;text-align:center;font-size:12px;color:#6b7280">'
  + 'Submitted via firealarmtestingpro.com</div></div>';

return [{
  json: {
    isValid: isValid,
    errorMessage: errorMessage,
    hasAttachment: hasAttachment,
    fileName: fileName,
    emailHtml: emailHtml,
    fullName: body.fullName || '',
    email: body.email || '',
    phone: body.phone || '',
    address: body.address || '',
    message: body.message || ''
  },
  binary: hasAttachment ? item.binary : undefined
}];
